const content = $input.item.json.content[0].text;
const v = $('Set Video Data').item.json;
let p;
try { p = JSON.parse(content); }
catch (e) {
  const m = content.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('Cannot parse Claude JSON: ' + content.slice(0, 300));
  p = JSON.parse(m[0]);
}
return { json: {
  telegram: p.telegram || '',
  vk: p.vk || '',
  linkedin: p.linkedin || '',
  reddit: p.reddit || { title: (p.youtube && p.youtube.title) || 'Новое видео' },
  youtube: p.youtube || { title: 'Видео', description: '' },
  website: p.website || {},
  video_url: v.video_url,
  file_id: v.file_id,
  chat_id: v.chat_id
}};

const w = $('Parse Content').item.json.website || {};
const y = $('Set YouTube Data').item.json;
const slug = (w.slug || ('video-' + Date.now())).toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
const title = w.title || 'Новое видео';
const seo = w.seo_desc || (w.card_desc || title);
const kw = w.keywords || 'видео, нейросети, маркетинг';
const cat = w.category || 'Видео';
const body = w.html_body || '<p>Смотрите видео выше.</p>';
const yid = y.youtube_id;
const thumb = y.thumb;
const now = new Date();
const date = now.toISOString().slice(0, 10);
const months = ['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
const dateLabel = now.getDate() + ' ' + months[now.getMonth()] + ' ' + now.getFullYear();
const url = '/video/' + slug + '/';
const canonical = 'https://saramudvlad.ru' + url;
const esc = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

const ld1 = JSON.stringify({ '@context':'https://schema.org','@type':'VideoObject', name:title, description:seo, thumbnailUrl:[thumb], uploadDate:date, contentUrl:y.youtube_url, embedUrl:'https://www.youtube.com/embed/'+yid, publisher:{ '@type':'Person', name:'Владислав Сарамуд', logo:{ '@type':'ImageObject', url:'https://saramudvlad.ru/avatar.webp' } } });
const ld2 = JSON.stringify({ '@context':'https://schema.org','@type':'BreadcrumbList', itemListElement:[ {'@type':'ListItem',position:1,name:'Главная',item:'https://saramudvlad.ru'}, {'@type':'ListItem',position:2,name:'Видео',item:'https://saramudvlad.ru/video/'}, {'@type':'ListItem',position:3,name:title} ] });

const html = `<!DOCTYPE html>
<html lang="ru">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, minimum-scale=1">
<title>${esc(title)} | Владислав Сарамуд</title>
<meta name="description" content="${esc(seo)}">
<meta name="keywords" content="${esc(kw)}">
<meta name="author" content="Владислав Сарамуд">
<link rel="canonical" href="${canonical}">
<meta property="og:type" content="video.other">
<meta property="og:url" content="${canonical}">
<meta property="og:title" content="${esc(title)}">
<meta property="og:description" content="${esc(seo)}">
<meta property="og:image" content="${thumb}">
<meta name="twitter:card" content="summary_large_image">
<meta name="twitter:image" content="${thumb}">
<link rel="icon" type="image/png" sizes="32x32" href="/favicon-32x32.png">
<script type="application/ld+json">${ld1}</scr`+`ipt>
<script type="application/ld+json">${ld2}</scr`+`ipt>
<link rel="stylesheet" href="/dist/tailwind.css">
<link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css" rel="stylesheet">
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;600;700;800&display=swap');
body{font-family:'Inter',sans-serif;background-color:#020617;color:#e2e8f0;}
.gradient-text{background:linear-gradient(to right,#fb7185,#f43f5e,#f97316);-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
article h2{font-size:1.75rem;font-weight:800;color:#fff;margin-top:2.5rem;margin-bottom:1.25rem;padding-bottom:.5rem;border-bottom:2px solid #f43f5e;}
article h3{font-size:1.25rem;font-weight:700;color:#fff;margin-top:1.75rem;margin-bottom:.75rem;}
article p{margin-bottom:1rem;line-height:1.8;color:#cbd5e1;}
article ul,article ol{margin:0 0 1.25rem 1.25rem;color:#cbd5e1;line-height:1.8;}
article ul li{list-style:disc;margin-bottom:.5rem;}article ol li{list-style:decimal;margin-bottom:.5rem;}
article pre{white-space:pre-wrap;word-break:break-word;background:#0b1120;border:1px solid #1e293b;border-radius:.75rem;padding:1.25rem;color:#e2e8f0;font-size:.9rem;line-height:1.6;font-family:ui-monospace,Menlo,monospace;margin:1rem 0 1.5rem;}
.video-wrap{position:relative;width:100%;padding-top:56.25%;border-radius:1rem;overflow:hidden;background:#0f172a;}
.video-wrap iframe{position:absolute;inset:0;width:100%;height:100%;border:0;}
</style>
</head>
<body class="antialiased selection:bg-rose-500 selection:text-white">
<nav class="border-b border-slate-800/50 sticky top-0 backdrop-blur-lg bg-slate-950/80 z-50"><div class="container mx-auto px-6 py-4 max-w-4xl"><div class="flex justify-between items-center"><a href="/video/" class="text-xl font-bold text-white hover:text-rose-400 transition"><i class="fas fa-arrow-left mr-2"></i>Все видео</a><a href="https://t.me/saramudvlad" target="_blank" class="text-rose-500 hover:text-rose-400 transition text-sm"><i class="fab fa-telegram"></i> Связаться</a></div></div></nav>
<main class="container mx-auto px-6 py-12 max-w-4xl">
<nav class="text-xs text-slate-500 mb-6"><a href="/" class="hover:text-rose-400">Главная</a> / <a href="/video/" class="hover:text-rose-400">Видео</a> / <span class="text-slate-400">${esc(cat)}</span></nav>
<div class="mb-4"><span class="text-xs font-bold text-rose-400 uppercase tracking-wider">${esc(cat)}</span></div>
<h1 class="text-3xl md:text-4xl font-extrabold text-white mb-4 leading-tight">${esc(title)}</h1>
<div class="flex items-center gap-4 text-xs text-slate-500 mb-8"><span><i class="far fa-calendar mr-1"></i>${dateLabel}</span><span><i class="far fa-user mr-1"></i>Владислав Сарамуд</span></div>
<div class="video-wrap mb-10"><iframe src="https://www.youtube.com/embed/${yid}" title="${esc(title)}" loading="lazy" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share" allowfullscreen></iframe></div>
<article>${body}</article>
<div class="mt-14 p-8 bg-slate-900/50 border border-rose-800/30 rounded-2xl text-center"><p class="text-slate-400 mb-6">Больше видео, промптов и кейсов — в Telegram-канале.</p><a href="https://t.me/saramudvlad" target="_blank" class="inline-flex items-center gap-2 px-8 py-4 bg-rose-600 hover:bg-rose-500 text-white font-bold rounded-xl transition"><i class="fab fa-telegram-plane"></i> Подписаться</a></div>
</main>
<footer class="py-10 text-center border-t border-slate-800/50 mt-16"><p class="text-slate-700 text-sm">© 2026 Владислав Сарамуд</p></footer>
</body>
</html>`;

const entry = { slug, title, desc: w.card_desc || seo, category: cat, categoryColor: 'rose', icon: 'fa-play', iconBg: 'from-rose-600 to-red-700', read: '5 мин', url, thumb, youtubeId: yid, date, dateLabel };

return { json: {
  page_path: 'video/' + slug + '/index.html',
  page_b64: Buffer.from(html, 'utf8').toString('base64'),
  entry,
  slug,
  commit_msg: 'Add video: ' + title
}};

const gh = $input.item.json;
const sha = gh.sha;
const current = JSON.parse(Buffer.from(gh.content, 'base64').toString('utf8'));
const entry = $('Build Video Page').item.json.entry;
const updated = [entry, ...current.filter(v => v.slug !== entry.slug)];
const b64 = Buffer.from(JSON.stringify(updated, null, 2), 'utf8').toString('base64');
return { json: { videos_b64: b64, sha, commit_msg: 'Update videos.json: ' + entry.slug } };
